INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (0.5, 0, 0, 107611, 0, 1, "シズルさまにエリコさま、\nどうかされたのですか？", 10, 905, 11, 19050041);
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES ("", "", "", 0, "", "", "", "", 905, 91, 19050042);
