INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES ("", 0.1, 1, 122611, 0.1, "45_yui_shy_loop", "45_yui_shy_in", 0, 945, 3, 19450030);
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES ("", 0.1, 1, 1, 0.1, "45_yui_shy_loop", "45_yui_shy_in", 0, 945, 3, 19450031);
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES ("", "", "", "vo_fpc", "", 0, "vo_fpc_30504", "", 945, 21, 19450032);
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (1, 0, 0, 122611, 0, 1, "…うん、やっちゃった…\nおっきなハートマーク…\nやっぱりこれは無しで！\nマコトちゃん食べてくれる！？", 5, 945, 11, 19450033);
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES ("", "", "", 0, "", "", "", "", 945, 91, 19450034);
