INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (1, 0, 0, 107811, 0, 1, "ん～、浮輪に乗ったりするのはいいけど\n泳ぐのはちょっと、って感じ。わかる？", 6, 946, 11, 19460023);
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES ("", "", "", 0, "", "", "", "", 946, 91, 19460024);
