INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (0.5, 0, 0, 107911, 0, 1, "わかるにゃ。あたし含めて猫の獣人族は\nそういう人多い気がするにゃ。", 7, 946, 11, 19460027);
